/// Configuration for the tree-sitter language pack.
///
/// Controls cache directory and which languages to pre-download.
/// Can be loaded from a TOML file, constructed programmatically,
/// or passed as a dict/object from language bindings.
///
/// # Example
///
/// ```no_run
/// use tree_sitter_language_pack::PackConfig;
///
/// let config = PackConfig {
///     cache_dir: None,
///     languages: Some(vec!["python".to_string(), "rust".to_string()]),
///     groups: None,
/// };
/// ```
#[derive(Clone, Default)]
#[wasm_bindgen]
pub struct WasmPackConfig {
    cache_dir: Option<String>,
    languages: Option<Vec<String>>,
    groups: Option<Vec<String>>,
}

#[wasm_bindgen]
impl WasmPackConfig {
    #[wasm_bindgen(constructor)]
    pub fn new(
        cache_dir: Option<String>,
        languages: Option<Vec<String>>,
        groups: Option<Vec<String>>,
    ) -> WasmPackConfig {
        WasmPackConfig {
            cache_dir,
            languages,
            groups,
        }
    }

    #[wasm_bindgen(getter, js_name = "cacheDir")]
    pub fn cache_dir(&self) -> Option<String> {
        self.cache_dir.clone()
    }

    #[wasm_bindgen(setter, js_name = "cacheDir")]
    pub fn set_cache_dir(&mut self, value: Option<String>) {
        self.cache_dir = value;
    }

    #[wasm_bindgen(getter)]
    pub fn languages(&self) -> Option<Vec<String>> {
        self.languages.clone()
    }

    #[wasm_bindgen(setter)]
    pub fn set_languages(&mut self, value: Option<Vec<String>>) {
        self.languages = value;
    }

    #[wasm_bindgen(getter)]
    pub fn groups(&self) -> Option<Vec<String>> {
        self.groups.clone()
    }

    #[wasm_bindgen(setter)]
    pub fn set_groups(&mut self, value: Option<Vec<String>>) {
        self.groups = value;
    }

    /// Load configuration from a TOML file.
    ///
    /// # Errors
    ///
    /// Returns an error if the file cannot be read or the TOML is invalid.
    ///
    /// # Example
    ///
    /// ```no_run
    /// use std::path::Path;
    /// use tree_sitter_language_pack::PackConfig;
    ///
    /// let config = PackConfig::from_toml_file(Path::new("language-pack.toml")).unwrap();
    /// ```
    #[allow(clippy::missing_errors_doc)]
    #[wasm_bindgen(js_name = "fromTomlFile")]
    pub fn from_toml_file(path: String) -> Result<WasmPackConfig, JsValue> {
        let result = tree_sitter_language_pack::PackConfig::from_toml_file(std::path::Path::new(&path))
            .map_err(|e| JsValue::from_str(&e.to_string()))?;
        Ok(result.into())
    }

    /// Discover configuration by searching for `language-pack.toml` in:
    ///
    /// 1. Current directory and up to 10 parent directories
    /// 2. `$XDG_CONFIG_HOME/tree-sitter-language-pack/config.toml`
    /// 3. `~/.config/tree-sitter-language-pack/config.toml`
    ///
    /// Returns `None` if no configuration file is found.
    ///
    /// # Example
    ///
    /// ```no_run
    /// use tree_sitter_language_pack::PackConfig;
    ///
    /// if let Some(config) = PackConfig::discover() {
    ///     println!("Found config with {:?} languages", config.languages);
    /// }
    /// ```
    #[wasm_bindgen]
    pub fn discover() -> Option<WasmPackConfig> {
        tree_sitter_language_pack::PackConfig::discover().map(Into::into)
    }
}

